
import { ParserRegistry } from "../../../../core/parser-registry";
import { radial_domain_position, radial_domain_styles } from "./radial-domain-encode";
import { radial_majorticks_position, radial_majorticks_styles } from "./radial-majorticks-encode";
import { radial_minorticks_position, radial_minorticks_styles } from "./radial-minorticks-encode";
import { radial_ticklabel_position, radial_ticklabel_styles } from "./radial-ticklabel-encode";
import { radial_ticks_position, radial_ticks_styles } from "./radial-ticks-encode";

export function radial_position() {
    const KEY = this.KEY;
    const position = this.helpers.position;
    position[KEY] = {};
}

export function radial_encode() {
    radial_position.call(this);

    radial_domain_position.call(this);
    radial_domain_styles.call(this);

    radial_ticks_position.call(this);
    radial_ticks_styles.call(this);

    radial_minorticks_position.call(this);
    radial_minorticks_styles.call(this);

    radial_majorticks_position.call(this);
    radial_majorticks_styles.call(this);

    radial_ticklabel_position.call(this);
    radial_ticklabel_styles.call(this);
}

ParserRegistry.encodes('radial', radial_encode);